import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: "balance" | "final" | "none";
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CurrencyAmount
              value={value}
              currency={currency}
              superscriptDecimals
            />
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
            />
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

function getValueColor(
  colorMode: CashflowTableSummaryValueCellProps["colorMode"],
  value: number | null,
) {
  if (value === null) {
    return "text.primary";
  }

  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import { Link, Stack, Typography } from "@mui/material";

import { Dot } from "@dfp/react-components";
import { CurrencyAmount } from "@dfp/react-currency-amount";
import { IconEdit05 } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import { useCockpit } from "../../CockpitContext.tsx";
import { useCashflowChartContext } from "../cashflow-chart/index.ts";
import { CashflowQualityIndicator } from "./CashflowQualityIndicator.tsx";

/**
 * Displays the current balance and a link to edit bank account selection.
 * Used in the chart legend area.
 */
export function CashflowBalanceSummary() {
  const { tt } = useTT();
  const { legendData } = useCashflowChartContext();
  const { openDialog } = useCockpit();
  const { currentBalance, currency, bankAccountCount, balanceQuality } =
    legendData;
  return (
    <Stack
      sx={{
        flexDirection: "row",
        alignItems: "center",
        gap: 1,
      }}
    >
      <CashflowQualityIndicator balanceQuality={balanceQuality} />
      {currentBalance !== null && (
        <Typography variant="h2">
          <CurrencyAmount
            value={currentBalance}
            currency={currency}
            superscriptDecimals
          />
        </Typography>
      )}
      <Dot color="custom.fillSecondaryActive" />
      <Link
        component="button"
        onClick={() => {
          openDialog("bankAccounts");
        }}
        sx={{
          display: "flex",
          alignItems: "center",
          gap: 0.5,
          color: "text.primary",
          textDecoration: "underline",
          cursor: "pointer",
        }}
      >
        {tt("chart.bankAccounts", { count: bankAccountCount })}
        <IconEdit05 />
      </Link>
    </Stack>
  );
}

