import { Chip, Tooltip, alpha, useTheme } from "@mui/material";

import { IconAlertSquare, IconAlertTriangle } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import type { BalanceQuality } from "../../index.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";

const QUALITY_TRANSLATION_KEY = {
  CALCULATED: "chart.qualityTooltipCalculated",
  IMPORTED: "chart.imported",
  DERIVED: "chart.qualityTooltipDerived",
} as const;

const ICON_SIZE = {
  sm: 16,
  md: 20,
} as const;

const CHIP_SIZE = {
  sm: 24,
  md: 30,
} as const;

type Props = {
  balanceQuality: BalanceQuality | null | undefined;
  size?: "md" | "sm";
  variant?: "icon" | "chip";
};

export function CashflowQualityIndicator({
  balanceQuality,
  size = "md",
  variant = "chip",
}: Props) {
  const { tt } = useTT();
  const theme = useTheme();

  if (balanceQuality !== "DERIVED" && balanceQuality !== "CALCULATED") {
    return null;
  }

  const qualityColor = getQualityThemeColor(theme, balanceQuality);
  const chipSx = {
    width: CHIP_SIZE[size],
    height: CHIP_SIZE[size],
    borderColor: qualityColor,
    backgroundColor: alpha(qualityColor, 0.1),
    color: qualityColor,
    "& .MuiChip-icon": { color: qualityColor },
  };

  const iconSx = {
    color: qualityColor,
    display: "inline-flex",
    alignItems: "center",
    justifyContent: "center",
  };

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle width={ICON_SIZE[size]} height={ICON_SIZE[size]} />
    ) : (
      <IconAlertSquare width={ICON_SIZE[size]} height={ICON_SIZE[size]} />
    );

  return (
    <Tooltip title={tt(QUALITY_TRANSLATION_KEY[balanceQuality])}>
      {variant === "icon" ? (
        <span style={iconSx}>{icon}</span>
      ) : (
        <Chip sx={chipSx} variant="outlined" icon={icon} />
      )}
    </Tooltip>
  );
}

import {
  Paper,
  Table,
  TableBody,
  TableContainer,
  TableHead,
} from "@mui/material";

import { useTT } from "../../useTT.ts";
import { CashflowTableCostsCategories } from "./CashflowTableCostsCategories.tsx";
import { CashflowTableFinalBalanceRow } from "./CashflowTableFinalBalanceRow.tsx";
import { CashflowTableHeader } from "./CashflowTableHeader.tsx";
import { CashflowTableIncomeCategories } from "./CashflowTableIncomeCategories.tsx";
import { CashflowTableNetBalanceRow } from "./CashflowTableNetBalanceRow.tsx";

/**
 * Main cashflow table component.
 *
 * Layout (top to bottom):
 * 1. Header
 * 2. Income section header (expandable) + income categories
 * 3. Costs section header (expandable) + cost categories
 * 4. Net Balance
 * 5. Final Balance
 *
 * Features:
 * - Collapsible Income and Costs sections with totals
 * - Dynamically renders all periods returned by the API
 * - Full content height (page scrolls instead of table)
 */
export function CashflowTable() {
  const { tt } = useTT();

  return (
    <TableContainer component={Paper}>
      <Table
        sx={{ tableLayout: "fixed", borderCollapse: "separate" }}
        aria-label={tt("cashflowTable.accessibility.tableLabel")}
      >
        <TableHead>
          <CashflowTableHeader />
        </TableHead>

        <TableBody>
          <CashflowTableIncomeCategories />
        </TableBody>
        <TableBody>
          <CashflowTableCostsCategories />
        </TableBody>

        <TableBody>
          <CashflowTableNetBalanceRow />
          <CashflowTableFinalBalanceRow />
        </TableBody>
      </Table>
    </TableContainer>
  );
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period, including quality information when available */
  finalBalance:
    | {
        value: number;
        balanceQuality: BalanceQuality;
      }
    | null;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
