};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

import type {
  CashFlowResponse,
  CashflowPeriod,
  CashflowTableData,
  CategoryType,
} from "../types/cashflow-table.types.ts";

/**
 * Transforms the API response from getCashFlowAndBalanceStates into table-ready data structure.
 *
 * Key transformations:
 * - Converts category arrays to Maps for efficient lookup
 * - Extracts all unique categories present in the data
 * - Renders all periods returned by the API (no padding or truncation)
 *
 * @param apiResponse - Response from getCashFlowAndBalanceStates API
 */
export function transformCashflowData(
  apiResponse: CashFlowResponse,
): CashflowTableData {
  const { cashFlowStates } = apiResponse;
  const sumArray = cashFlowStates?.sumArray ?? [];
  const { sumAggregationalGranularity } = cashFlowStates ?? {};

  // Transform API periods to table periods
  const periods: CashflowPeriod[] = sumArray.map((period, index: number) => {
    // Convert category arrays to Maps
    const incomeCategories = new Map<CategoryType, number>();
    period.incomeCategorySum?.forEach((cat) => {
      incomeCategories.set(cat.category as CategoryType, cat.amount);
    });

    const costsCategories = new Map<CategoryType, number>();
    period.costsCategorySum?.forEach((cat) => {
      costsCategories.set(cat.category as CategoryType, cat.amount);
    });

    const netBalance = period.netChange;
    const finalBalance = period.finalBalance
      ? {
          value: period.finalBalance.balance,
          balanceQuality: period.finalBalance.balanceQuality,
        }
      : null;

    return {
      id: `period-${index}-${period.dateFrom}`,
      dateFrom: period.dateFrom,
      dateTo: period.dateTo,
      income: period.income,
      costs: period.costs,
      netBalance,
      finalBalance,
      incomeCategories,
      costsCategories,
      transactionCount: period.transactionCount,
      // Progress percentage would be calculated here if API provides planned amounts
      progressPercentage: undefined,
    };
  });

  // Extract all unique categories that have data
  const allIncomeCategories = new Set<CategoryType>();
  const allCostsCategories = new Set<CategoryType>();

  periods.forEach((period) => {
    period.incomeCategories.forEach((_, category) => {
      allIncomeCategories.add(category);
    });
    period.costsCategories.forEach((_, category) => {
      allCostsCategories.add(category);
    });
  });

  return {
    periods,
    granularity: sumAggregationalGranularity || "1M",
    categories: {
      income: Array.from(allIncomeCategories),
      costs: Array.from(allCostsCategories),
    },
  };
}

import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: "balance" | "final" | "none";
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
              variant="icon"
            />
            <CurrencyAmount
              notation="compact"
              value={value}
              currency={currency}
              naturalPrecision
            />
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

function getValueColor(
  colorMode: CashflowTableSummaryValueCellProps["colorMode"],
  value: number | null,
) {
  if (value === null) {
    return "text.primary";
  }

  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import { type ReactNode, useMemo, useState } from "react";

import type {
  BalancePoint,
  BalanceQuality,
  CashFlowInterval,
  CashflowChartContextType,
  ChartViewMode,
  Interval,
  LegendData,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../../utils/index.ts";
import { segmentLineChartQuality } from "../line-chart/index.ts";
import {
  CashflowChartContext,
  useCashflowChartContext,
} from "./cashflowChart.context.ts";

type CashflowChartProviderProps = {
  children: ReactNode;
  data?: {
    cashFlowStates?: {
      sumArray?: CashFlowInterval[];
    };
    aggregatedBalanceValues?: Record<string, BalancePoint> | BalancePoint[];
    todayAggregatedBalance?: {
      balance: number;
      balanceQuality: BalanceQuality;
    };
  };
  // Interval state from parent (where the query is made)
  interval: Interval;
  setInterval: (interval: Interval) => void;
  /** Currency code for display (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the query */
  bankAccountCount: number;
};

/**
 * Provider component for cashflow chart context
 * Manages view state, selection, and data transformations
 */
export function CashflowChartProvider({
  children,
  data,
  interval,
  setInterval,
  currency,
  bankAccountCount,
}: CashflowChartProviderProps) {
  const [viewMode, setViewMode] = useState<ChartViewMode>("bar");

  const cashFlowData = useMemo(
    () => data?.cashFlowStates?.sumArray || [],
    [data],
  );

  const balanceData = useMemo(() => {
    const rawBalanceData = data?.aggregatedBalanceValues;

    if (!rawBalanceData) {
      return {};
    }

    if (!Array.isArray(rawBalanceData)) {
      return rawBalanceData;
    }

    return rawBalanceData.reduce(
      (acc, balancePoint) => {
        if (balancePoint.date) {
          acc[balancePoint.date] = balancePoint;
        }
        return acc;
      },
      {} as Record<string, BalancePoint>,
    );
  }, [data?.aggregatedBalanceValues]);

  const barChartData = useMemo(
    () => transformToBarChartData(cashFlowData, interval),
    [cashFlowData, interval],
  );

  const lineChartData = useMemo(
    () => transformToLineChartData(balanceData, cashFlowData),
    [balanceData, cashFlowData],
  );

  const segmentationResult = useMemo(
    () => segmentLineChartQuality(lineChartData),
    [lineChartData],
  );

  // Compute current balance from the dedicated API field
  const legendData = useMemo<LegendData>(() => {
    const todayBalance = data?.todayAggregatedBalance;

    if (!todayBalance) {
      return { currentBalance: null, currency, bankAccountCount };
    }

    return {
      currentBalance: todayBalance.balance,
      currency,
      bankAccountCount,
      balanceQuality: todayBalance.balanceQuality,
    };
  }, [data?.todayAggregatedBalance, currency, bankAccountCount]);

  const contextValue = useMemo<CashflowChartContextType>(
    () => ({
      viewMode,
      setViewMode,
      interval,
      setInterval,
      legendData,
      barChartData,
      lineChartData: segmentationResult.chartData,
      lineChartSegmentKeys: {
        calculatedSegmentKeys: segmentationResult.calculatedSegmentKeys,
        importedSegmentKeys: segmentationResult.importedSegmentKeys,
        derivedSegmentKeys: segmentationResult.derivedSegmentKeys,
      },
    }),
    [
      viewMode,
      interval,
      setInterval,
      barChartData,
      segmentationResult,
      legendData,
    ],
  );

  return (
    <CashflowChartContext.Provider value={contextValue}>
      {children}
    </CashflowChartContext.Provider>
  );
}

